 45→interface PostRequestHandler {
 46→    suspend fun handlePostRequest(uri: String, bytes: ByteArray): ByteArray
 47→}
 48→
 49→suspend fun handleCollectionPostRequest(methodName: String, bytes: ByteArray): ByteArray? {
 50→    return when (methodName) {
 51→        "i18nResources" -> withCol { i18nResourcesRaw(bytes) }
 52→        "getGraphPreferences" -> withCol { getGraphPreferencesRaw() }
 53→        "setGraphPreferences" -> withCol { setGraphPreferencesRaw(bytes) }
 54→        "graphs" -> withCol { graphsRaw(bytes) }
 55→        "getNotetypeNames" -> withCol { getNotetypeNamesRaw(bytes) }
 56→        "getDeckNames" -> withCol { getDeckNamesRaw(bytes) }
 57→        "getCsvMetadata" -> withCol { getCsvMetadataRaw(bytes) }
 58→        "importCsv" -> importCsvRaw(bytes)
 59→        "importJsonFile" -> importJsonFileRaw(bytes)
 60→        "importDone" -> bytes
 61→        "completeTag" -> withCol { completeTagRaw(bytes) }
 62→        "getFieldNames" -> withCol { getFieldNamesRaw(bytes) }
 63→        "cardStats" -> withCol { cardStatsRaw(bytes) }
 64→        "getDeckConfig" -> withCol { getDeckConfigRaw(bytes) }
 65→        "getDeckConfigsForUpdate" -> withCol { getDeckConfigsForUpdateRaw(bytes) }
 66→        "computeFsrsWeights" -> withCol { computeFsrsWeightsRaw(bytes) }
 67→        "computeOptimalRetention" -> withCol { computeOptimalRetentionRaw(bytes) }
 68→        "evaluateWeights" -> withCol { evaluateWeightsRaw(bytes) }
 69→        "getImageForOcclusion" -> withCol { getImageForOcclusionRaw(bytes) }
 70→        "getImageOcclusionNote" -> withCol { getImageOcclusionNoteRaw(bytes) }
 71→        "getImageForOcclusionFields" -> withCol { getImageOcclusionFieldsRaw(bytes) }
 72→        "setWantsAbort" -> getBackend().setWantsAbortRaw(bytes)
 73→        "latestProgress" -> getBackend().latestProgressRaw(bytes)
 74→        "congratsInfo" -> withCol { congratsInfoRaw(bytes) }
 75→        else -> null
 76→    }
 77→}
 78→
 79→suspend fun FragmentActivity.handleUiPostRequest(methodName: String, bytes: ByteArray): ByteArray? {
 80→    return when (methodName) {
 81→        "searchInBrowser" -> searchInBrowser(bytes)
 82→        "updateDeckConfigs" -> updateDeckConfigsRaw(bytes)
 83→        "addImageOcclusionNote" -> {
 84→            val data = withCol { addImageOcclusionNoteRaw(bytes) }
 85→            undoableOp { OpChanges.parseFrom(data) }
 86→            launchCatchingTask {
 87→                // Allow time for toast message to appear before closing editor
 88→                delay(1000)
 89→                setResult(Activity.RESULT_OK)
 90→                finish()
 91→            }
 92→            data
 93→        }
 94→        "updateImageOcclusionNote" -> {
 95→            val data = withCol {
 96→                updateImageOcclusionNoteRaw(bytes)
 97→            }
 98→            undoableOp { OpChanges.parseFrom(data) }
 99→            launchCatchingTask {
100→                // Allow time for toast message to appear before closing editor
101→                delay(1000)
102→                setResult(NoteEditor.RESULT_UPDATED_IO_NOTE)
103→                finish()
104→            }
105→            data
106→        }
107→        else -> null
108→    }
109→}
